using sv_00af12029e3548e7b5cbe1cbc22eeab5.Models;

namespace sv_00af12029e3548e7b5cbe1cbc22eeab5.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _recipes = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with tomato, mozzarella, and basil.", 30),
            new(2, "Carbonara", "Creamy pasta with pancetta, egg, and pecorino.", 25),
            new(3, "Tiramisu", "Layered coffee-flavored Italian dessert.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp and peanuts.", 20),
            new(5, "Green Curry", "Spicy coconut curry with vegetables and chicken.", 35),
            new(6, "Tom Yum Soup", "Hot and sour soup with lemongrass and prawns.", 25),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Pork tacos with pineapple and cilantro.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime and onion.", 10),
            new(9, "Churros", "Fried dough pastry with cinnamon sugar.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_recipes.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_00af12029e3548e7b5cbe1cbc22eeab5.Models
@using sv_00af12029e3548e7b5cbe1cbc22eeab5.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IDisposable

<h3>Recipes</h3>

@if (_isRefreshing && _recipes is not null)
{
    <p><em>Refreshing…</em></p>
}

@if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-primary" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    var sorted = GetSortedRecipes();
    <ul>
        @foreach (var recipe in sorted)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <br />
                <small>Prep time: @recipe.PrepTimeMinutes min</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _errorMessage;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        // Only reload when the cuisine changes, not when sort changes.
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var cancellationToken = _cts.Token;

        _errorMessage = null;
        _isRefreshing = _recipes is not null;

        var cuisineId = CuisineId;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(cuisineId, cancellationToken);

            _recipes = result;
            _loadedCuisineId = cuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // We cancelled this ourselves (user navigated to another cuisine or left the page).
        }
        catch (OperationCanceledException)
        {
            // Cancelled externally or timed out — not by our token.
            Logger.LogWarning("Recipe loading for cuisine {CuisineId} was cancelled or timed out.", cuisineId);
            _isRefreshing = false;
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}.", cuisineId);
            _isRefreshing = false;
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private List<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return new();

        return Sort?.ToLowerInvariant() switch
        {
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes).ToList(),
            "newest" => _recipes.OrderByDescending(r => r.Id).ToList(),
            _ => _recipes.ToList(),
        };
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

