namespace sv_00af12029e3548e7b5cbe1cbc22eeab5.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _recipes = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with tomato, mozzarella, and basil.", 30),
            new(2, "Carbonara", "Creamy pasta with pancetta, egg, and pecorino.", 25),
            new(3, "Tiramisu", "Layered coffee-flavored Italian dessert.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp and peanuts.", 20),
            new(5, "Green Curry", "Spicy coconut curry with vegetables and chicken.", 35),
            new(6, "Tom Yum Soup", "Hot and sour soup with lemongrass and prawns.", 25),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Pork tacos with pineapple and cilantro.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime and onion.", 10),
            new(9, "Churros", "Fried dough pastry with cinnamon sugar.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_recipes.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

